import { makeSimpleQuestion } from './base'
import type { Question, Topic } from './types'

const SOURCE = 'Floe career agent-generated qualifications ethics ops second supplement'
const DEFAULT_FLAW = 'This is a plausible workplace move, but it does not fit the evidence, risk, or professional standard in the scenario.'

function q(
  id: number,
  topic: Topic,
  chapter: string,
  title: string,
  prompt: string,
  correct: string,
  wrong: string[],
  lesson: string,
): Question {
  return makeSimpleQuestion(
    id,
    topic,
    chapter,
    title,
    prompt,
    correct,
    wrong.map((label) => [label, DEFAULT_FLAW, lesson] as [string, string, string]),
    lesson,
    SOURCE,
  )
}

